import { useState, useEffect, useRef, useCallback } from 'react';
import { Send, Image, Gift, User, MessageCircle, Phone, Mail, AlertCircle, Check, Clock } from 'lucide-react';
import axios from 'axios';

interface Message {
  id: string;
  username: string;
  text: string;
  type: 'text' | 'image' | 'giftcard';
  fileUrl?: string;
  fileName?: string;
  sender: 'user' | 'admin';
  timestamp: string;
  status: 'sent' | 'delivered' | 'read';
}

interface ChatUser {
  username: string;
  joinedAt: string;
  lastActive: string;
}

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:3001';

export default function ChatPage() {
  const [username, setUsername] = useState('');
  const [isRegistered, setIsRegistered] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [fileType, setFileType] = useState<'image' | 'giftcard' | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const giftcardInputRef = useRef<HTMLInputElement>(null);
  const pollingRef = useRef<NodeJS.Timeout | null>(null);

  // Load user data from localStorage on mount
  useEffect(() => {
    const savedUsername = localStorage.getItem('chat_username');
    const savedMessages = localStorage.getItem('chat_messages');
    
    if (savedUsername) {
      setUsername(savedUsername);
      setIsRegistered(true);
    }
    
    if (savedMessages) {
      try {
        const parsed = JSON.parse(savedMessages);
        setMessages(parsed);
      } catch (e) {
        console.error('Failed to parse saved messages:', e);
      }
    }
  }, []);

  // Save messages to localStorage whenever they change
  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('chat_messages', JSON.stringify(messages));
    }
  }, [messages]);

  // Scroll to bottom when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Poll for new messages
  useEffect(() => {
    if (isRegistered && username) {
      const pollMessages = async () => {
        try {
          const response = await axios.get(`${API_URL}/api/messages/${username}`);
          if (response.data.messages) {
            setMessages(prev => {
              const newMessages = response.data.messages;
              // Merge with existing messages, avoiding duplicates
              const existingIds = new Set(prev.map(m => m.id));
              const uniqueNew = newMessages.filter((m: Message) => !existingIds.has(m.id));
              return [...prev, ...uniqueNew];
            });
          }
        } catch (err) {
          console.error('Polling error:', err);
        }
      };

      pollMessages(); // Initial poll
      pollingRef.current = setInterval(pollMessages, 3000); // Poll every 3 seconds

      return () => {
        if (pollingRef.current) {
          clearInterval(pollingRef.current);
        }
      };
    }
  }, [isRegistered, username]);

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (username.trim().length < 3) {
      setError('Username must be at least 3 characters');
      return;
    }
    
    localStorage.setItem('chat_username', username);
    setIsRegistered(true);
    setError('');
    
    // Send welcome message
    const welcomeMessage: Message = {
      id: Date.now().toString(),
      username,
      text: `Welcome ${username}! You can now chat directly. Send messages, photos, or gift cards.`,
      type: 'text',
      sender: 'admin',
      timestamp: new Date().toISOString(),
      status: 'read'
    };
    setMessages([welcomeMessage]);
  };

  const sendMessage = async (text: string, type: 'text' | 'image' | 'giftcard' = 'text', fileData?: { url: string; name: string }) => {
    if (!text.trim() && type === 'text') return;
    
    setIsLoading(true);
    setError('');

    try {
      const messageData = {
        username,
        text,
        type,
        fileUrl: fileData?.url,
        fileName: fileData?.name,
        sender: 'user',
        timestamp: new Date().toISOString()
      };

      // Add to local state immediately
      const newMessage: Message = {
        id: Date.now().toString(),
        ...messageData,
        status: 'sent'
      };
      setMessages(prev => [...prev, newMessage]);

      // Send to server
      const response = await axios.post(`${API_URL}/api/send-message`, messageData);
      
      if (response.data.success) {
        // Update message status
        setMessages(prev => 
          prev.map(m => 
            m.id === newMessage.id ? { ...m, status: 'delivered' } : m
          )
        );
      }
    } catch (err) {
      console.error('Send error:', err);
      setError('Failed to send message. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputMessage.trim()) {
      sendMessage(inputMessage);
      setInputMessage('');
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'giftcard') => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { // 10MB limit
        setError('File size must be less than 10MB');
        return;
      }
      setSelectedFile(file);
      setFileType(type);
    }
  };

  const handleFileUpload = async () => {
    if (!selectedFile || !fileType) return;

    setIsLoading(true);
    setError('');

    try {
      const formData = new FormData();
      formData.append('file', selectedFile);
      formData.append('username', username);
      formData.append('type', fileType);

      const response = await axios.post(`${API_URL}/api/upload`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      if (response.data.success) {
        await sendMessage(
          fileType === 'image' ? '📷 Image' : '🎁 Gift Card',
          fileType,
          { url: response.data.fileUrl, name: selectedFile.name }
        );
        setSelectedFile(null);
        setFileType(null);
      }
    } catch (err) {
      console.error('Upload error:', err);
      setError('Failed to upload file. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const formatTime = (timestamp: string) => {
    return new Date(timestamp).toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const formatDate = (timestamp: string) => {
    return new Date(timestamp).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric'
    });
  };

  // Group messages by date
  const groupedMessages = messages.reduce((groups, message) => {
    const date = formatDate(message.timestamp);
    if (!groups[date]) {
      groups[date] = [];
    }
    groups[date].push(message);
    return groups;
  }, {} as Record<string, Message[]>);

  if (!isRegistered) {
    return (
      <div className="min-h-screen pt-32 pb-20">
        <div className="container-custom">
          <div className="max-w-md mx-auto">
            <div className="text-center mb-8">
              <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-gradient-to-br from-blue-500 to-blue-700 flex items-center justify-center">
                <MessageCircle className="w-10 h-10 text-white" />
              </div>
              <h1 className="text-3xl font-bold text-white mb-2">Join the Conversation</h1>
              <p className="text-gray-400">Create a unique username to start chatting</p>
            </div>

            <form onSubmit={handleRegister} className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Choose Your Username
                </label>
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                  <input
                    type="text"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    placeholder="Enter username..."
                    className="w-full pl-12 pr-4 py-4 rounded-xl bg-white/5 border border-white/10 text-white placeholder-gray-500 focus:border-blue-500 focus:outline-none transition-colors"
                    minLength={3}
                    required
                  />
                </div>
                {error && (
                  <div className="flex items-center space-x-2 mt-2 text-red-400 text-sm">
                    <AlertCircle className="w-4 h-4" />
                    <span>{error}</span>
                  </div>
                )}
              </div>

              <button
                type="submit"
                className="w-full btn-primary py-4"
              >
                Start Chatting
              </button>

              <div className="text-center text-sm text-gray-500">
                <p>Your username will be used for all conversations</p>
                <p className="mt-1">Chat history will be saved on your device</p>
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pt-20 pb-4">
      <div className="container-custom h-[calc(100vh-6rem)]">
        <div className="h-full flex flex-col bg-white/5 border border-white/10 rounded-2xl overflow-hidden">
          {/* Header */}
          <div className="flex items-center justify-between p-4 border-b border-white/10 bg-white/5">
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-500 to-blue-700 flex items-center justify-center">
                <User className="w-5 h-5 text-white" />
              </div>
              <div>
                <div className="font-semibold text-white">{username}</div>
                <div className="flex items-center space-x-1 text-xs text-green-400">
                  <span className="w-2 h-2 rounded-full bg-green-400" />
                  <span>Online</span>
                </div>
              </div>
            </div>
            <button
              onClick={() => {
                localStorage.removeItem('chat_username');
                localStorage.removeItem('chat_messages');
                setIsRegistered(false);
                setUsername('');
                setMessages([]);
              }}
              className="text-sm text-gray-400 hover:text-white transition-colors"
            >
              Logout
            </button>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {Object.entries(groupedMessages).map(([date, dateMessages]) => (
              <div key={date}>
                <div className="flex items-center justify-center mb-4">
                  <div className="px-4 py-1 rounded-full bg-white/10 text-xs text-gray-400">
                    {date}
                  </div>
                </div>
                {dateMessages.map((message) => (
                  <div
                    key={message.id}
                    className={`flex ${message.sender === 'user' ? 'justify-end' : 'justify-start'} mb-4`}
                  >
                    <div
                      className={`max-w-[70%] ${
                        message.sender === 'user'
                          ? 'chat-bubble-user'
                          : 'chat-bubble-admin'
                      } p-3`}
                    >
                      {message.type === 'image' && message.fileUrl && (
                        <div className="mb-2">
                          <img
                            src={message.fileUrl}
                            alt="Shared image"
                            className="max-w-full rounded-lg cursor-pointer hover:opacity-90 transition-opacity"
                            onClick={() => window.open(message.fileUrl, '_blank')}
                          />
                        </div>
                      )}
                      
                      {message.type === 'giftcard' && message.fileUrl && (
                        <div className="mb-2 p-4 rounded-lg bg-gradient-to-br from-yellow-500/20 to-orange-500/20 border border-yellow-500/30">
                          <div className="flex items-center space-x-2 mb-2">
                            <Gift className="w-5 h-5 text-yellow-400" />
                            <span className="font-semibold text-yellow-400">Gift Card</span>
                          </div>
                          <a
                            href={message.fileUrl}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="text-sm text-blue-400 hover:underline"
                          >
                            {message.fileName || 'Download Gift Card'}
                          </a>
                        </div>
                      )}
                      
                      {message.text && (
                        <p className="text-white">{message.text}</p>
                      )}
                      
                      <div className="flex items-center justify-end space-x-1 mt-1">
                        <span className="text-xs text-gray-400">
                          {formatTime(message.timestamp)}
                        </span>
                        {message.sender === 'user' && (
                          <span className="text-xs">
                            {message.status === 'read' ? (
                              <Check className="w-3 h-3 text-blue-400" />
                            ) : message.status === 'delivered' ? (
                              <Check className="w-3 h-3 text-gray-400" />
                            ) : (
                              <Clock className="w-3 h-3 text-gray-400" />
                            )}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            ))}
            <div ref={messagesEndRef} />
          </div>

          {/* File Preview */}
          {selectedFile && (
            <div className="px-4 py-2 bg-white/5 border-t border-white/10">
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-2">
                  {fileType === 'image' ? (
                    <Image className="w-5 h-5 text-blue-400" />
                  ) : (
                    <Gift className="w-5 h-5 text-yellow-400" />
                  )}
                  <span className="text-sm text-gray-300 truncate max-w-[200px]">
                    {selectedFile.name}
                  </span>
                </div>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={handleFileUpload}
                    disabled={isLoading}
                    className="px-3 py-1 rounded-lg bg-blue-500 text-white text-sm hover:bg-blue-600 transition-colors disabled:opacity-50"
                  >
                    {isLoading ? 'Sending...' : 'Send'}
                  </button>
                  <button
                    onClick={() => {
                      setSelectedFile(null);
                      setFileType(null);
                    }}
                    className="px-3 py-1 rounded-lg bg-white/10 text-gray-400 text-sm hover:bg-white/20 transition-colors"
                  >
                    Cancel
                  </button>
                </div>
              </div>
            </div>
          )}

          {/* Error */}
          {error && (
            <div className="px-4 py-2 bg-red-500/10 border-t border-red-500/20">
              <div className="flex items-center space-x-2 text-red-400 text-sm">
                <AlertCircle className="w-4 h-4" />
                <span>{error}</span>
              </div>
            </div>
          )}

          {/* Input */}
          <form onSubmit={handleSendMessage} className="p-4 border-t border-white/10 bg-white/5">
            <div className="flex items-center space-x-2">
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="p-3 rounded-xl bg-white/10 text-gray-400 hover:text-white hover:bg-white/20 transition-colors"
                title="Send Image"
              >
                <Image className="w-5 h-5" />
              </button>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={(e) => handleFileSelect(e, 'image')}
                className="hidden"
              />

              <button
                type="button"
                onClick={() => giftcardInputRef.current?.click()}
                className="p-3 rounded-xl bg-white/10 text-gray-400 hover:text-yellow-400 hover:bg-white/20 transition-colors"
                title="Send Gift Card"
              >
                <Gift className="w-5 h-5" />
              </button>
              <input
                ref={giftcardInputRef}
                type="file"
                accept="image/*,.pdf"
                onChange={(e) => handleFileSelect(e, 'giftcard')}
                className="hidden"
              />

              <input
                type="text"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                placeholder="Type a message..."
                className="flex-1 px-4 py-3 rounded-xl bg-white/10 border border-white/10 text-white placeholder-gray-500 focus:border-blue-500 focus:outline-none transition-colors"
                disabled={isLoading}
              />

              <button
                type="submit"
                disabled={isLoading || !inputMessage.trim()}
                className="p-3 rounded-xl bg-blue-500 text-white hover:bg-blue-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Send className="w-5 h-5" />
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}
