export default function TimelinePage() {
  const pageRef = useRef<HTMLDivElement>(null);
  const lineRef = useRef<SVGPathElement>(null);
  const eventRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const triggers: ScrollTrigger[] = [];

    // Animate timeline line
    if (lineRef.current) {
      const lineTrigger = ScrollTrigger.create({
        trigger: lineRef.current,
        start: 'top 80%',
        end: 'bottom 20%',
        onUpdate: (self) => {
          if (lineRef.current) {
            const length = lineRef.current.getTotalLength();
            lineRef.current.style.strokeDasharray = `${length}`;
            lineRef.current.style.strokeDashoffset = `${length * (1 - self.progress)}`;
          }
        }
      });
      triggers.push(lineTrigger);
    }

    // Animate events
    eventRefs.current.forEach((ref, index) => {
      if (ref) {
        const trigger = ScrollTrigger.create({
          trigger: ref,
          start: 'top 85%',
          onEnter: () => {
            gsap.fromTo(ref,
              { opacity: 0, x: index % 2 === 0 ? -50 : 50, rotateY: index % 2 === 0 ? -15 : 15 },
              { opacity: 1, x: 0, rotateY: 0, duration: 0.8, ease: 'power3.out' }
            );
          },
          once: true
        });
        triggers.push(trigger);
      }
    });

    return () => {
      triggers.forEach(trigger => trigger.kill());
    };
  }, []);

  return (
    <div ref={pageRef} className="min-h-screen">
      {/* Hero Section */}
      <section className="relative pt-32 pb-20">
        <div className="container-custom">
          <div className="text-center max-w-3xl mx-auto">
            <div className="inline-flex items-center space-x-2 px-4 py-2 rounded-full bg-blue-500/10 border border-blue-500/30 mb-6">
              <Zap className="w-4 h-4 text-blue-400" />
              <span className="text-sm text-blue-400 font-medium">The Journey</span>
            </div>

            <h1 className="text-5xl md:text-6xl font-black mb-6">
              <span className="text-white">Timeline of</span>
              <br />
              <span className="text-gradient-blue">Innovation</span>
            </h1>

            <p className="text-lg text-gray-400">
              From a young programmer in South Africa to one of the most influential 
              entrepreneurs in history. Explore the key moments that shaped Elon Musk's journey.
            </p>
          </div>
        </div>
      </section>

      {/* Timeline */}
      <section className="section-padding relative">
        <div className="container-custom">
          <div className="relative max-w-4xl mx-auto">
            {/* SVG Line */}
            <svg 
              className="absolute left-1/2 -translate-x-1/2 top-0 h-full w-4 hidden md:block"
              preserveAspectRatio="none"
            >
              <path
                ref={lineRef}
                d={`M 8 0 Q 8 ${timelineEvents.length * 150 / 2} 8 ${timelineEvents.length * 150}`}
                fill="none"
                stroke="#0066CC"
                strokeWidth="2"
                strokeLinecap="round"
              />
            </svg>

            {/* Events */}
            <div className="space-y-12 md:space-y-24">
              {timelineEvents.map((event, index) => {
                const Icon = event.icon;
                const isLeft = index % 2 === 0;

                return (
                  <div
                    key={index}
                    ref={el => eventRefs.current[index] = el}
                    className={`relative flex flex-col md:flex-row items-center ${
                      isLeft ? 'md:flex-row' : 'md:flex-row-reverse'
                    }`}
                  >
                    {/* Content Card */}
                    <div className={`w-full md:w-5/12 ${isLeft ? 'md:text-right md:pr-12' : 'md:text-left md:pl-12'}`}>
                      <div className="p-6 rounded-2xl bg-white/5 border border-white/10 hover:border-white/20 transition-all duration-300 group">
                        <div className={`inline-flex items-center space-x-2 px-3 py-1 rounded-lg bg-gradient-to-br ${event.color} mb-4`}>
                          <Icon className="w-4 h-4 text-white" />
                          <span className="text-white text-xs font-medium">{event.category}</span>
                        </div>
                        
                        <div className="text-4xl font-black text-gradient mb-2">{event.year}</div>
                        <h3 className="text-xl font-bold text-white mb-2">{event.title}</h3>
                        <p className="text-gray-400 text-sm leading-relaxed">{event.description}</p>
                      </div>
                    </div>

                    {/* Center Node */}
                    <div className="relative z-10 my-4 md:my-0">
                      <div className={`w-16 h-16 rounded-full bg-gradient-to-br ${event.color} flex items-center justify-center glow-blue`}>
                        <Icon className="w-8 h-8 text-white" />
                      </div>
                      <div className="absolute inset-0 rounded-full bg-gradient-to-br ${event.color} animate-ping opacity-20" />
                    </div>

                    {/* Empty Space for Alignment */}
                    <div className="hidden md:block md:w-5/12" />
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </section>

      {/* Quote Section */}
      <section className="section-padding">
        <div className="container-custom">
          <div className="relative rounded-3xl overflow-hidden p-12 md:p-20">
            <div className="absolute inset-0 bg-gradient-to-br from-blue-600/10 to-purple-600/10" />
            <div className="absolute inset-0 backdrop-blur-sm" />
            <div className="relative max-w-3xl mx-auto text-center">
              <h2 className="text-3xl md:text-4xl font-bold text-white mb-8">
                Persistence Through Failure
              </h2>
              <blockquote className="text-xl md:text-2xl text-gray-300 italic leading-relaxed mb-8">
                "Failure is an option here. If things are not failing, you are not innovating enough. 
                If something is important enough, even if the odds are against you, you should still do it."
              </blockquote>
              <div className="flex items-center justify-center space-x-4">
                <div className="w-12 h-12 rounded-full bg-gradient-to-br from-blue-500 to-blue-700 flex items-center justify-center">
                  <span className="text-white font-bold">EM</span>
                </div>
                <div className="text-left">
                  <div className="text-white font-semibold">Elon Musk</div>
                  <div className="text-gray-500 text-sm">On Taking Risks</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
}
