import { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

interface NodeProps {
  position: [number, number, number];
}

function Node({ position }: NodeProps) {
  const meshRef = useRef<THREE.Mesh>(null);
  const lightRef = useRef<THREE.PointLight>(null);
  
  useFrame((state) => {
    if (meshRef.current && lightRef.current) {
      const time = state.clock.elapsedTime;
      const pulse = Math.sin(time * 2 + position[0] * 0.5) * 0.3 + 0.7;
      meshRef.current.scale.setScalar(0.05 + pulse * 0.02);
      lightRef.current.intensity = pulse * 0.5;
    }
  });

  return (
    <group position={position}>
      <mesh ref={meshRef}>
        <sphereGeometry args={[1, 16, 16]} />
        <meshBasicMaterial color="#0066CC" transparent opacity={0.8} />
      </mesh>
      <pointLight ref={lightRef} color="#0066CC" distance={3} intensity={0.5} />
    </group>
  );
}

interface ConnectionProps {
  start: [number, number, number];
  end: [number, number, number];
}

function Connection({ start, end }: ConnectionProps) {
  const lineRef = useRef<THREE.Line>(null);
  
  const geometry = useMemo(() => {
    const geo = new THREE.BufferGeometry().setFromPoints([
      new THREE.Vector3(...start),
      new THREE.Vector3(...end)
    ]);
    return geo;
  }, [start, end]);

  useFrame((state) => {
    if (lineRef.current) {
      const material = lineRef.current.material as THREE.LineBasicMaterial;
      const time = state.clock.elapsedTime;
      const pulse = Math.sin(time * 3 + start[0] * 0.3) * 0.4 + 0.6;
      material.opacity = pulse * 0.3;
    }
  });

  return (
    <line ref={lineRef} geometry={geometry}>
      <lineBasicMaterial color="#0066CC" transparent opacity={0.2} />
    </line>
  );
}

function NeuralNetwork() {
  const groupRef = useRef<THREE.Group>(null);
  
  const { nodes, connections } = useMemo(() => {
    const nodePositions: [number, number, number][] = [];
    const connectionPairs: [number, number][] = [];
    
    // Create nodes in a 3D grid
    for (let x = -4; x <= 4; x += 1.5) {
      for (let y = -3; y <= 3; y += 1.5) {
        for (let z = -2; z <= 2; z += 1.5) {
          if (Math.random() > 0.6) {
            nodePositions.push([x + (Math.random() - 0.5) * 0.5, y + (Math.random() - 0.5) * 0.5, z]);
          }
        }
      }
    }
    
    // Create connections between nearby nodes
    for (let i = 0; i < nodePositions.length; i++) {
      for (let j = i + 1; j < nodePositions.length; j++) {
        const dist = Math.sqrt(
          Math.pow(nodePositions[i][0] - nodePositions[j][0], 2) +
          Math.pow(nodePositions[i][1] - nodePositions[j][1], 2) +
          Math.pow(nodePositions[i][2] - nodePositions[j][2], 2)
        );
        if (dist < 2.5 && Math.random() > 0.7) {
          connectionPairs.push([i, j]);
        }
      }
    }
    
    return { nodes: nodePositions, connections: connectionPairs };
  }, []);

  useFrame((state) => {
    if (groupRef.current) {
      groupRef.current.rotation.y = state.clock.elapsedTime * 0.05;
      groupRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.1) * 0.1;
    }
  });

  return (
    <group ref={groupRef}>
      {nodes.map((position, index) => (
        <Node key={index} position={position} />
      ))}
      {connections.map(([i, j], index) => (
        <Connection key={index} start={nodes[i]} end={nodes[j]} />
      ))}
    </group>
  );
}

function ParticleField() {
  const pointsRef = useRef<THREE.Points>(null);
  
  const particles = useMemo(() => {
    const positions = new Float32Array(200 * 3);
    for (let i = 0; i < 200; i++) {
      positions[i * 3] = (Math.random() - 0.5) * 20;
      positions[i * 3 + 1] = (Math.random() - 0.5) * 20;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 10;
    }
    return positions;
  }, []);

  useFrame((state) => {
    if (pointsRef.current) {
      pointsRef.current.rotation.y = state.clock.elapsedTime * 0.02;
    }
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={200}
          array={particles}
          itemSize={3}
        />
      </bufferGeometry>
      <pointsMaterial
        size={0.03}
        color="#0066CC"
        transparent
        opacity={0.4}
        sizeAttenuation
      />
    </points>
  );
}

export default function NeuralNetworkBackground() {
  return (
    <div className="fixed inset-0 -z-10">
      <Canvas
        camera={{ position: [0, 0, 8], fov: 60 }}
        dpr={[1, 1.5]}
        gl={{ antialias: true, alpha: true }}
      >
        <color attach="background" args={['#000000']} />
        <fog attach="fog" args={['#000000', 5, 15]} />
        <ambientLight intensity={0.1} />
        <NeuralNetwork />
        <ParticleField />
      </Canvas>
    </div>
  );
}
